        }
        C[row * N + col] = alpha * sum + beta * C[row * N + col];
    }
}

__global__ void naive_int8_gemm(
    const int8_t* __restrict__ A,
    const int8_t* __restrict__ B,
    int32_t* __restrict__ C,
    int M, int N, int K,
    int32_t alpha, int32_t beta) {
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;
    if (row < M && col < N) {
        int32_t sum = 0;
        for (int k = 0; k < K; k++) {
            sum += (int32_t)A[row * K + k] * (int32_t)B[k * N + col];
        }
        C[row * N + col] = alpha * sum + beta * C[row * N + col];
    }
}

__global__ void naive_int4_gemm(
    const int4b_t* __restrict__ A,  // Packed 4-bit integers
    const int4b_t* __restrict__ B,
    int32_t* __restrict__ C,
    int M, int N, int K,
    int32_t alpha, int32_t beta) {
    // Unpacking 4-bit values from packed representation
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;
    if (row < M && col < N) {
        int32_t sum = 0;
        for (int k = 0; k < K; k++) {
            int8_t a_val = unpack_int4(A, row, k, K);  // Extract 4-bit value
            int8_t b_val = unpack_int4(B, k, col, N);
            sum += (int32_t)a_val * (int32_t)b_val;
        }
        C[row * N + col] = alpha * sum + beta * C[row * N + col];
    }
}

__global__ void naive_binary_gemm(
    const uint32_t* __restrict__ A,  // Packed 32 bits per word
    const uint32_t* __restrict__ B,
    int32_t* __restrict__ C,
    int M, int N, int K_bits,
    int32_t alpha, int32_t beta) {
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;
    if (row < M && col < N) {
        int32_t sum = 0;
        for (int k = 0; k < K_bits / 32; k++) {
            uint32_t a_word = A[row * (K_bits/32) + k];
            uint32_t b_word = B[k * N + col];
            // XOR + popcount = number of differing bits
            sum += __popc(a_word ^ b_word);
        }
        // Convert popcount to +1/-1 inner product
        C[row * N + col] = alpha * (K_bits - 2*sum) + beta * C[row * N + col];
    }
}
